from harness.metrics import precision_at_k, recall_at_k


def test_recall_at_k_is_partial_when_some_relevant_missing():
    # only kb_a is relevant and present in top-3 of two relevant docs -> 0.5
    assert recall_at_k(["kb_a", "kb_b", "kb_c"], {"kb_a", "kb_z"}, 3) == 0.5


def test_recall_at_k_respects_k_cutoff():
    # relevant doc sits at rank 2 but k=1 -> not found -> 0.0
    assert recall_at_k(["kb_x", "kb_a"], {"kb_a"}, 1) == 0.0


def test_precision_at_k_counts_only_relevant_in_top_k():
    assert abs(precision_at_k(["kb_a", "kb_b", "kb_c"], {"kb_a"}, 3) - (1.0 / 3.0)) < 1e-6
